<div class="review-layout"><section class="panel"><h2>Submission evidence</h2><dl class="detail-list"><div><dt>Description</dt><dd><?= esc($dataset['description']) ?></dd></div><div><dt>Research</dt><dd><?= esc($dataset['research_title']) ?></dd></div><div><dt>Project head</dt><dd><?= esc($dataset['project_head']) ?></dd></div><div><dt>Category and type</dt><dd><?= esc($dataset['category'] . ' · ' . $dataset['data_type'] . ' · ' . $dataset['file_format']) ?></dd></div><div><dt>Source</dt><dd><?= esc($dataset['source_type'] . ($dataset['source_link'] ? ' · ' . $dataset['source_link'] : '')) ?></dd></div><div><dt>Access requested</dt><dd><?= esc($dataset['access_type']) ?></dd></div></dl><?php if ($latestFile): ?><a class="button secondary" href="<?= site_url('review/' . $stage . '/' . $review['id'] . '/download') ?>">Download protected ZIP</a><?php endif; ?><h3>Version history</h3><?php foreach ($versions as $version): ?><p>v<?= esc($version['version']) ?> · <?= esc($version['change_summary'] ?: 'No summary') ?></p><?php endforeach; ?></section>
