<section class="panel"><h2>Complete review history</h2><?php foreach ($history as $item): ?><p><strong><?= esc(ucfirst($item['stage'])) ?> round <?= esc($item['review_round']) ?></strong> · <?= esc($item['status']) ?> · <?= esc($item['reviewer_name'] ?? 'Unknown') ?><?= $item['comments'] ? '<br>' . esc($item['comments']) : '' ?></p><?php endforeach; ?></section>
